import{_ as a,o,c,a3 as t}from"./chunks/framework.aYYe0dfI.js";const m=JSON.parse('{"title":"Module extract:compiler","description":"extract:compiler 模块负责加载、解析和归一化编译数据库（如 compile_commands.json），并提供对单个编译条目进行标准化处理的核心流程。它公开定义了 CompileEntry、CompilationDatabase 和 CompDbError 等数据结构，用于表示编译命令、数据库及错误信息。模块的公开函数涵盖从文件路径加载数据库（load_compdb）、在数据库中按源文件查找条目（lookup）、标准化条目中的文件路径与参数（normalize_entry_file、normalize_argument_path、sanitize_driver_arguments、sanitize_tool_arguments）、生成唯一编译签名与缓存键（build_compile_signature、ensure_cache_key）、缓存工具链查询结果（query_toolchain_cached）以及最终基于归一化后的条目创建编译器实例（create_compiler_instance）等关键操作，为后续代码提取与分析提供稳定可重复的编译上下文。","frontmatter":{"title":"Module extract:compiler","description":"extract:compiler 模块负责加载、解析和归一化编译数据库（如 compile_commands.json），并提供对单个编译条目进行标准化处理的核心流程。它公开定义了 CompileEntry、CompilationDatabase 和 CompDbError 等数据结构，用于表示编译命令、数据库及错误信息。模块的公开函数涵盖从文件路径加载数据库（load_compdb）、在数据库中按源文件查找条目（lookup）、标准化条目中的文件路径与参数（normalize_entry_file、normalize_argument_path、sanitize_driver_arguments、sanitize_tool_arguments）、生成唯一编译签名与缓存键（build_compile_signature、ensure_cache_key）、缓存工具链查询结果（query_toolchain_cached）以及最终基于归一化后的条目创建编译器实例（create_compiler_instance）等关键操作，为后续代码提取与分析提供稳定可重复的编译上下文。","layout":"doc","template":"doc"},"headers":[],"relativePath":"zh/clore/modules/extract/compiler.md","filePath":"zh/clore/modules/extract/compiler.md"}'),r={name:"zh/clore/modules/extract/compiler.md"};function i(d,e,l,s,n,p){return o(),c("div",null,[...e[0]||(e[0]=[t('<h1 id="module-extract-compiler" tabindex="-1">Module <code>extract:compiler</code> <a class="header-anchor" href="#module-extract-compiler" aria-label="Permalink to &quot;Module `extract:compiler`&quot;">​</a></h1><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p><code>extract:compiler</code> 模块负责加载、解析和归一化编译数据库（如 <code>compile_commands``.json</code>），并提供对单个编译条目进行标准化处理的核心流程。它公开定义了 <code>CompileEntry</code>、<code>CompilationDatabase</code> 和 <code>CompDbError</code> 等数据结构，用于表示编译命令、数据库及错误信息。模块的公开函数涵盖从文件路径加载数据库（<code>load_compdb</code>）、在数据库中按源文件查找条目（<code>lookup</code>）、标准化条目中的文件路径与参数（<code>normalize_entry_file</code>、<code>normalize_argument_path</code>、<code>sanitize_driver_arguments</code>、<code>sanitize_tool_arguments</code>）、生成唯一编译签名与缓存键（<code>build_compile_signature</code>、<code>ensure_cache_key</code>）、缓存工具链查询结果（<code>query_toolchain_cached</code>）以及最终基于归一化后的条目创建编译器实例（<code>create_compiler_instance</code>）等关键操作，为后续代码提取与分析提供稳定可重复的编译上下文。</p><h2 id="imports" tabindex="-1">Imports <a class="header-anchor" href="#imports" aria-label="Permalink to &quot;Imports&quot;">​</a></h2><ul><li><code>std</code></li><li><a href="./../support/"><code>support</code></a></li></ul><h2 id="imported-by" tabindex="-1">Imported By <a class="header-anchor" href="#imported-by" aria-label="Permalink to &quot;Imported By&quot;">​</a></h2><ul><li><a href="./ast"><code>extract:ast</code></a></li><li><a href="./cache"><code>extract:cache</code></a></li><li><a href="./scan"><code>extract:scan</code></a></li></ul><h2 id="types" tabindex="-1">Types <a class="header-anchor" href="#types" aria-label="Permalink to &quot;Types&quot;">​</a></h2><h3 id="clore-extract-compdberror" tabindex="-1"><code>clore::extract::CompDbError</code> <a class="header-anchor" href="#clore-extract-compdberror" aria-label="Permalink to &quot;`clore::extract::CompDbError`&quot;">​</a></h3><p>Declaration: <code>extract/compiler.cppm:38</code></p><p>Definition: <code>extract/compiler.cppm:38</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p><code>clore::extract::CompDbError</code> 是一个简单的错误类型，内部仅包含一个 <code>std::string</code> 类型的 <code>message</code> 成员。该结构体没有自定义构造函数、析构函数或赋值运算符，完全依赖编译器生成的默认版本，因此它作为平凡可复制且可移动的类型。其唯一的不变性是 <code>message</code> 在逻辑上应表示一条无歧义的错误信息，但该结构体自身不对此施加任何校验或约束，所有错误文本的构建与解释均由上层调用代码负责。<code>message</code> 成员使用标准字符串存储，使得该类型能够自然地参与异常抛出或值返回的错误处理流程。</p><h4 id="invariants" tabindex="-1">Invariants <a class="header-anchor" href="#invariants" aria-label="Permalink to &quot;Invariants&quot;">​</a></h4><ul><li>The <code>message</code> member is always default-constructible and movable.</li></ul><h4 id="key-members" tabindex="-1">Key Members <a class="header-anchor" href="#key-members" aria-label="Permalink to &quot;Key Members&quot;">​</a></h4><ul><li><code>message</code></li></ul><h4 id="usage-patterns" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Caught or checked by callers of <code>clore::extract</code> functions that may fail.</li></ul><h3 id="clore-extract-compilationdatabase" tabindex="-1"><code>clore::extract::CompilationDatabase</code> <a class="header-anchor" href="#clore-extract-compilationdatabase" aria-label="Permalink to &quot;`clore::extract::CompilationDatabase`&quot;">​</a></h3><p>Declaration: <code>extract/compiler.cppm:31</code></p><p>Definition: <code>extract/compiler.cppm:31</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p>内部结构由两个主要数据容器构成：<code>entries</code> 是一个 <code>std::vector&lt;CompileEntry&gt;</code>，用于存储编译数据库中的所有编译条目；<code>toolchain_cache</code> 是一个 <code>std::unordered_map&lt;std::string, std::vector&lt;std::string&gt;&gt;</code>，作为缓存层，将工具链标识符（字符串）映射到其对应的编译标志序列，从而避免重复解析相同的工具链配置。两个容器之间没有显式的约束，但缓存的设计预期与 <code>entries</code> 中的工具链引用保持一致。</p><p><code>has_cached_toolchain</code> 方法的实现直接检查 <code>toolchain_cache</code> 是否非空，返回 <code>true</code> 表示缓存中至少包含一组解析后的工具链数据，否则返回 <code>false</code>。由于该方法不带参数且为 const 限定，它仅反映缓存整体的填充状态，而不针对特定工具链标识符进行查询。该实现作为轻量级门卫函数，允许调用方在需要填充或重用缓存前快速判断是否已有缓存数据。</p><h4 id="member-functions" tabindex="-1">Member Functions <a class="header-anchor" href="#member-functions" aria-label="Permalink to &quot;Member Functions&quot;">​</a></h4><h5 id="clore-extract-compilationdatabase-has-cached-toolchain" tabindex="-1"><code>clore::extract::CompilationDatabase::has_cached_toolchain</code> <a class="header-anchor" href="#clore-extract-compilationdatabase-has-cached-toolchain" aria-label="Permalink to &quot;`clore::extract::CompilationDatabase::has_cached_toolchain`&quot;">​</a></h5><p>Declaration: <code>extract/compiler.cppm:35</code></p><p>Definition: <code>extract/compiler.cppm:229</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><h6 id="implementation" tabindex="-1">Implementation <a class="header-anchor" href="#implementation" aria-label="Permalink to &quot;Implementation&quot;">​</a></h6><div class="language-cpp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">auto</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> CompilationDatabase</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">::</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">has_cached_toolchain</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">() </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -&gt;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> bool</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    return</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> !</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">toolchain_cache.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">empty</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">();</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h3 id="clore-extract-compileentry" tabindex="-1"><code>clore::extract::CompileEntry</code> <a class="header-anchor" href="#clore-extract-compileentry" aria-label="Permalink to &quot;`clore::extract::CompileEntry`&quot;">​</a></h3><p>Declaration: <code>extract/compiler.cppm:21</code></p><p>Definition: <code>extract/compiler.cppm:21</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p>结构体 <code>clore::extract::CompileEntry</code> 直接容纳从编译数据库记录中解析出的四个原始字段：<code>file</code>、<code>directory</code>、<code>arguments</code> 和可选的 <code>source_hash</code>。其中 <code>file</code> 存储源文件相对路径，<code>directory</code> 记录编译命令的工作目录，<code>arguments</code> 保留完整的命令行参数列表。<code>normalized_file</code> 与 <code>compile_signature</code> 是两个派生字段，分别代表规范化后的文件路径和根据规范化文件与参数计算出的 64 位编译签名，用于唯一标识该编译条目。<code>cache_key</code> 则是一个字符串，通常由 <code>compile_signature</code> 和 <code>source_hash</code> 联合构成，为后续缓存查找提供快速索引。</p><p>所有成员均在默认构造函数中初始化为空字符串或零值。在加载条目时，<code>normalized_file</code>、<code>compile_signature</code> 和 <code>cache_key</code> 会依次计算并赋值，确保它们在后续使用前已正确填充。<code>source_hash</code> 仅当源文件内容被访问时才记录哈希值，因此其类型为 <code>std::optional</code>，允许未赋值状态。这些字段共同构成了一个紧凑的编译单元描述，供提取流程下游步骤（如去重、缓存或分析）直接使用。</p><h4 id="invariants-1" tabindex="-1">Invariants <a class="header-anchor" href="#invariants-1" aria-label="Permalink to &quot;Invariants&quot;">​</a></h4><ul><li>字段的默认值为空字符串、空向量、零或 <code>std::nullopt</code>，表示使用前应被填充。</li></ul><h4 id="key-members-1" tabindex="-1">Key Members <a class="header-anchor" href="#key-members-1" aria-label="Permalink to &quot;Key Members&quot;">​</a></h4><ul><li><code>file</code></li><li><code>directory</code></li><li><code>arguments</code></li><li><code>normalized_file</code></li><li><code>compile_signature</code></li><li><code>source_hash</code></li><li><code>cache_key</code></li></ul><h4 id="usage-patterns-1" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-1" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>用于表示从编译数据库或构建系统中提取的单个编译条目。</li><li>可能用于编译缓存或重新执行的输入。</li></ul><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><h3 id="clore-extract-build-compile-signature" tabindex="-1"><code>clore::extract::build_compile_signature</code> <a class="header-anchor" href="#clore-extract-build-compile-signature" aria-label="Permalink to &quot;`clore::extract::build_compile_signature`&quot;">​</a></h3><p>Declaration: <code>extract/compiler.cppm:58</code></p><p>Definition: <code>extract/compiler.cppm:110</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p><code>clore::extract::build_compile_signature</code> 首先检查 <code>entry</code> 的 <code>normalized_file</code> 是否非空且 <code>compile_signature</code> 字段非零：若成立则直接返回缓存的签名，避免重复计算。否则，它会确保 <code>normalized_file</code> 可用——若 <code>entry.normalized_file</code> 为空则调用 <code>normalize_entry_file</code> 生成它，否则直接复用已有值——然后委托给命名空间内的 <code>build_compile_signature_impl</code> 执行实际签名计算。</p><p>该函数的核心设计是通过预检查缓存短路后续开销，并统一规范化文件路径。其依赖关系局限于 <code>normalize_entry_file</code>（用于解析 <code>CompileEntry</code> 的文件路径）以及 <code>build_compile_signature_impl</code>（内部实现签名算法），后者负责解析编译参数、加载编译数据库、实例化编译器调用等更复杂的流程。</p><h4 id="side-effects" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>entry.normalized_file</code></li><li><code>entry.compile_signature</code></li><li><code>clore::extract::normalize_entry_file</code> (reads <code>entry</code>)</li></ul><h4 id="usage-patterns-2" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-2" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Used to obtain a stable identifier for a compile entry.</li><li>Likely used for caching or detecting changes in compile configurations.</li></ul><h3 id="clore-extract-create-compiler-instance" tabindex="-1"><code>clore::extract::create_compiler_instance</code> <a class="header-anchor" href="#clore-extract-create-compiler-instance" aria-label="Permalink to &quot;`clore::extract::create_compiler_instance`&quot;">​</a></h3><p>Declaration: <code>extract/compiler.cppm:65</code></p><p>Definition: <code>extract/compiler.cppm:297</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p><code>create_compiler_instance</code> 首先调用 <code>sanitize_driver_arguments</code> 清理传入的 <code>CompileEntry</code> 以生成有效的 <code>driver_args</code>。若 <code>driver_args</code> 为空则直接返回 <code>nullptr</code>。接着创建一个物理文件系统 <code>vfs</code>，并基于 <code>DiagnosticOptions</code> 和 <code>IgnoringDiagConsumer</code> 初始化一个 <code>DiagnosticsEngine</code>。随后调用 <code>parse_compiler_invocation</code> 解析 <code>driver_args</code>、<code>entry.file</code>、<code>vfs</code> 和 <code>diagnostics</code>，尝试构造 <code>CompilerInvocation</code>；若解析失败或 <code>FrontendOptions::Inputs</code> 为空，均返回 <code>nullptr</code>。成功获得 <code>invocation</code> 后，会设置其 <code>DisableFree</code> 为 <code>false</code> 并将 <code>WorkingDir</code> 设为 <code>entry.directory</code>。最终使用该 <code>invocation</code> 构造 <code>CompilerInstance</code>，依次设置 <code>vfs</code>、创建诊断器与文件管理器，并通过 <code>createTarget</code> 检查目标是否可用；任意步骤失败则返回 <code>nullptr</code>，否则返回构建好的实例。</p><p>该函数依赖 <code>sanitize_driver_arguments</code>、<code>parse_compiler_invocation</code> 以及 <code>clang</code> 与 <code>llvm::vfs</code> 的基础设施，通过组装一个完整的编译器实例为后续的提取工作提供执行环境。</p><h4 id="side-effects-1" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-1" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><ul><li>Allocates memory for a <code>clang::CompilerInstance</code> and associated objects</li><li>Accesses the file system via physical VFS creation and target creation</li></ul><h4 id="reads-from-1" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-1" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li>entry (const <code>CompileEntry</code>&amp;): reads entry<code>.file</code> and entry<code>.directory</code></li></ul><h4 id="usage-patterns-3" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-3" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Typically called by extraction pipeline to obtain a compiler instance for parsing source files</li></ul><h3 id="clore-extract-ensure-cache-key" tabindex="-1"><code>clore::extract::ensure_cache_key</code> <a class="header-anchor" href="#clore-extract-ensure-cache-key" aria-label="Permalink to &quot;`clore::extract::ensure_cache_key`&quot;">​</a></h3><p>Declaration: <code>extract/compiler.cppm:60</code></p><p>Definition: <code>extract/compiler.cppm:225</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p>Implementation: <a href="./functions/ensure-cache-key">Implementation</a></p><p>函数 <code>clore::extract::ensure_cache_key</code> 完全委托给内部的 <code>ensure_cache_key_impl</code>，后者负责为给定的 <code>CompileEntry</code> 计算并设置 <code>cache_key</code> 字段。实现流程首先调用 <code>normalize_entry_file</code> 获取规范化路径，然后通过 <code>sanitize_driver_arguments</code> 清理参数列表，并尝试用 <code>parse_compiler_invocation</code> 解析出 <code>CompilerInvocation</code>，从中提取 <code>frontend_inputs</code> 并调用 <code>try_hash_source_file</code> 计算 <code>source_hash</code>。接着利用 <code>build_compile_signature</code>（内部委托给 <code>build_compile_signature_impl</code>）生成最终的签名值，此过程还会查询 <code>toolchain_cache</code>（通过 <code>query_toolchain_cached</code>）并可能加载编译数据库（<code>load_compdb</code>）以补充缺失上下文，最终将签名写入 <code>entry.cache_key</code> 以确保每个条目拥有唯一的缓存标识。</p><h4 id="side-effects-2" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-2" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><ul><li>Modifies the <code>CompileEntry</code> by setting its cache key.</li></ul><h4 id="reads-from-2" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-2" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li>Parameter <code>entry</code> (reference to <code>CompileEntry</code>).</li></ul><h4 id="writes-to" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to" aria-label="Permalink to &quot;Writes To&quot;">​</a></h4><ul><li>Parameter <code>entry</code> (the <code>CompileEntry</code> object is mutated).</li></ul><h4 id="usage-patterns-4" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-4" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Called by <code>query_toolchain_cached</code> before attempting to use cached toolchain information to ensure the entry has a valid cache key.</li></ul><h3 id="clore-extract-ensure-cache-key-impl" tabindex="-1"><code>clore::extract::ensure_cache_key_impl</code> <a class="header-anchor" href="#clore-extract-ensure-cache-key-impl" aria-label="Permalink to &quot;`clore::extract::ensure_cache_key_impl`&quot;">​</a></h3><p>Declaration: <code>extract/compiler.cppm:119</code></p><p>Definition: <code>extract/compiler.cppm:119</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p>Implementation: <a href="./functions/ensure-cache-key-impl">Implementation</a></p><p><code>ensure_cache_key_impl</code> 通过依次填充 <code>CompileEntry</code> 的四个关键字段来构造缓存键。它首先调用 <code>normalize_entry_file</code> 将条目的源文件路径规范化，结果写入 <code>entry.normalized_file</code>。然后调用 <code>build_compile_signature_impl</code> 基于该规范化路径生成编译签名，存入 <code>entry.compile_signature</code>。接着用 <code>try_hash_source_file</code> 尝试哈希源文件，结果存入 <code>entry.source_hash</code>；该调用可能返回空，但函数在此处不检查其结果——缓存键的最终构建依赖 <code>clore::support::build_cache_key</code>，它仅使用规范化路径和编译签名组成 <code>entry.cache_key</code>。</p><p>整个流程是线性的，无分支或错误处理；它假定所有被调用的辅助函数均能成功完成，并将结果直接赋值给传入的 <code>CompileEntry</code>。该函数是 <code>ensure_cache_key</code> 的内部实现，将缓存键的构造分解为独立的子步骤，便于测试和复用。</p><h4 id="side-effects-3" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-3" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><ul><li>Modifies the fields of the passed <code>CompileEntry&amp;</code></li><li>Reads the source file for hashing via <code>try_hash_source_file</code></li></ul><h4 id="reads-from-3" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-3" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li>The <code>CompileEntry</code> parameter <code>entry</code></li><li>The file system via <code>normalize_entry_file</code> and <code>try_hash_source_file</code></li></ul><h4 id="writes-to-1" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to-1" aria-label="Permalink to &quot;Writes To&quot;">​</a></h4><ul><li><code>entry.normalized_file</code></li><li><code>entry.compile_signature</code></li><li><code>entry.source_hash</code></li><li><code>entry.cache_key</code></li></ul><h4 id="usage-patterns-5" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-5" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Called by <code>clore::extract::ensure_cache_key</code></li></ul><h3 id="clore-extract-load-compdb" tabindex="-1"><code>clore::extract::load_compdb</code> <a class="header-anchor" href="#clore-extract-load-compdb" aria-label="Permalink to &quot;`clore::extract::load_compdb`&quot;">​</a></h3><p>Declaration: <code>extract/compiler.cppm:42</code></p><p>Definition: <code>extract/compiler.cppm:127</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p>该函数首先检查输入路径对应的文件是否存在，若不存在则返回一个 <code>CompDbError</code>。接着调用 <code>clang::tooling::JSONCompilationDatabase::loadFromFile</code> 解析 JSON 数据库，解析失败同样返回错误。成功时遍历所有编译命令，为每个命令构造一个 <code>CompileEntry</code>，依次填充其 <code>file</code>、<code>directory</code> 和 <code>arguments</code> 字段，并对每个 entry 调用 <code>ensure_cache_key</code> 生成缓存键，最后将 entry 移入 <code>CompilationDatabase</code> 的 <code>entries</code> 向量。此过程依赖 <code>clang::tooling</code> 的 JSON 解析能力，以及内部辅助函数 <code>ensure_cache_key</code> 对每个条目进行键值计算，最终以日志记录加载的条目数量并返回数据库对象。</p><h4 id="side-effects-4" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-4" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><ul><li>Reads file system to check existence and read <code>compile_commands.json</code></li><li>Allocates memory for the returned <code>CompilationDatabase</code> and its entries</li><li>Calls <code>ensure_cache_key</code> which may modify each <code>CompileEntry</code></li><li>Outputs a log message via <code>logging::info</code></li></ul><h4 id="reads-from-4" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-4" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>path</code> parameter (<code>std::string_view</code>)</li><li>File system: <code>compile_commands.json</code> at the given <code>path</code></li><li><code>entry.file</code>, <code>entry.directory</code>, <code>entry.arguments</code> from each parsed compile command</li></ul><h4 id="writes-to-2" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to-2" aria-label="Permalink to &quot;Writes To&quot;">​</a></h4><ul><li>Returned <code>std::expected&lt;CompilationDatabase, CompDbError&gt;</code> (includes <code>CompilationDatabase</code> on success)</li><li>Each <code>CompileEntry</code> passed to <code>ensure_cache_key</code> (cache key field)</li><li>Log output via <code>logging::info</code></li></ul><h4 id="usage-patterns-6" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-6" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Typically invoked at the start of the extraction pipeline to obtain the compilation database</li><li>Used in conjunction with other extraction functions like <code>query_toolchain_cached</code> or <code>extract_project_async</code></li></ul><h3 id="clore-extract-lookup" tabindex="-1"><code>clore::extract::lookup</code> <a class="header-anchor" href="#clore-extract-lookup" aria-label="Permalink to &quot;`clore::extract::lookup`&quot;">​</a></h3><p>Declaration: <code>extract/compiler.cppm:44</code></p><p>Definition: <code>extract/compiler.cppm:164</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p>函数 <code>clore::extract::lookup</code> 遍历 <code>CompilationDatabase</code> 的 <code>entries</code> 容器，对每个 <code>CompileEntry</code> 执行两步路径标准化：首先通过 <code>normalize_argument_path</code> 将查询的文件路径 <code>file</code> 与当前条目的 <code>directory</code> 合并得到候选路径 <code>candidate</code>；然后利用 <code>normalize_entry_file</code> 将条目的 <code>file</code> 字段转换为绝对路径（若 <code>normalized_file</code> 已缓存则直接使用）。最后使用 <code>std::filesystem::path</code> 的相等比较判断 <code>candidate</code> 与 <code>normalized_entry</code> 是否匹配，将所有匹配的条目指针收集到 <code>std::vector&lt;const CompileEntry*&gt;</code> 中并返回。</p><p>该函数依赖于 <code>normalize_argument_path</code> 和 <code>normalize_entry_file</code> 两个辅助函数，后者会调用 <code>std::filesystem::weakly_canonical</code> 完成路径解析。内部控制流为简单的线性扫描，未涉及缓存或提前退出，时间复杂度为 O(n)。</p><h4 id="side-effects-5" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-5" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-5" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-5" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>db.entries</code></li><li><code>entry.directory</code></li><li><code>entry.normalized_file</code></li></ul><h4 id="usage-patterns-7" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-7" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Lookup compile entries for a specific source file</li></ul><h3 id="clore-extract-normalize-argument-path" tabindex="-1"><code>clore::extract::normalize_argument_path</code> <a class="header-anchor" href="#clore-extract-normalize-argument-path" aria-label="Permalink to &quot;`clore::extract::normalize_argument_path`&quot;">​</a></h3><p>Declaration: <code>extract/compiler.cppm:49</code></p><p>Definition: <code>extract/compiler.cppm:188</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p>该函数将传入的 <code>path</code> 与 <code>directory</code> 组合并解析为绝对、规范的文件系统路径。算法首先判断 <code>path</code> 是否为相对路径：若是，则将其与 <code>directory</code> 拼接；接着通过 <code>std::filesystem::absolute</code> 转换为绝对路径（忽略错误），再调用 <code>lexically_normal</code> 进行词法规范化。最后尝试使用 <code>weakly_canonical</code> 获取强规范形式——此步骤依赖底层文件系统判断是否存在符号链接或目录问题，若失败则直接返回词法规范化后的结果。整个流程依赖 <code>std::filesystem</code> 提供的路径操作与错误处理机制。</p><h4 id="side-effects-6" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-6" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><ul><li>Accesses the filesystem via <code>std::filesystem::weakly_canonical</code> to resolve symlinks and verify path existence.</li></ul><h4 id="reads-from-6" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-6" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>std::string_view path</code> parameter</li><li><code>std::string_view directory</code> parameter</li><li>Filesystem state (for symlink resolution and existence checks)</li></ul><h4 id="usage-patterns-8" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-8" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Normalizes file paths from compilation database entries</li><li>Standardizes paths before comparison or indexing in extraction pipeline</li></ul><h3 id="clore-extract-normalize-entry-file" tabindex="-1"><code>clore::extract::normalize_entry_file</code> <a class="header-anchor" href="#clore-extract-normalize-entry-file" aria-label="Permalink to &quot;`clore::extract::normalize_entry_file`&quot;">​</a></h3><p>Declaration: <code>extract/compiler.cppm:56</code></p><p>Definition: <code>extract/compiler.cppm:91</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p>Implementation: <a href="./functions/normalize-entry-file">Implementation</a></p><p>函数 <code>clore::extract::normalize_entry_file</code> 通过组合 <code>std::filesystem</code> 操作将 <code>entry.file</code> 规范化为绝对路径并解析链接依赖。首先检查路径是否为相对路径，若是则与 <code>entry.directory</code> 拼接；接着调用 <code>std::filesystem::absolute</code> 生成绝对形式，然后通过 <code>lexically_normal</code> 做词法上的规范化。为处理符号链接，进一步尝试 <code>weakly_canonical</code>：若失败（如路径不存在或权限不足）则回退到词法规范化结果，最终以 Unix 风格返回 <code>generic_string</code>。</p><p>该函数主要依赖 <code>std::filesystem::path</code> 及其错误处理（通过 <code>std::error_code</code>），不涉及外部文件系统缓存或其他模块。控制流简洁：仅处理相对路径分支和回退分支，确保在无法解析真实路径时仍返回格式一致的结果。</p><h4 id="side-effects-7" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-7" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-7" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-7" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>entry.file</code></li><li><code>entry.directory</code></li></ul><h4 id="usage-patterns-9" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-9" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Used by <code>build_compile_signature</code> to create a stable file key</li><li>Used by <code>ensure_cache_key_impl</code> to normalize the file path before caching</li></ul><h3 id="clore-extract-query-toolchain-cached" tabindex="-1"><code>clore::extract::query_toolchain_cached</code> <a class="header-anchor" href="#clore-extract-query-toolchain-cached" aria-label="Permalink to &quot;`clore::extract::query_toolchain_cached`&quot;">​</a></h3><p>Declaration: <code>extract/compiler.cppm:62</code></p><p>Definition: <code>extract/compiler.cppm:233</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p>函数 <code>clore::extract::query_toolchain_cached</code> 通过缓存机制返回与给定 <code>CompileEntry</code> 关联的工具链参数。它首先检查 <code>entry.arguments</code> 是否为空，若为空则直接返回空向量。否则，使用 <code>entry.cache_key</code> 作为查找键；若该键为空，则复制 <code>entry</code> 并调用 <code>ensure_cache_key</code> 生成缓存键。随后在 <code>db.toolchain_cache</code> 中查找该键，若命中则返回对应的已缓存 <code>std::vector&lt;std::string&gt;</code>。</p><p>若缓存未命中，函数调用 <code>sanitize_tool_arguments</code> 对原始 <code>entry</code> 进行清理，将结果存入 <code>db.toolchain_cache</code>（键为步骤中确定的 <code>key</code>），并返回该结果。该实现依赖于 <code>ensure_cache_key</code>（用于保证缓存键的一致性）和 <code>sanitize_tool_arguments</code>（负责实际的参数规范化与提取）。</p><h4 id="side-effects-8" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-8" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><ul><li>Modifies the toolchain cache of the <code>CompilationDatabase</code> object</li></ul><h4 id="reads-from-8" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-8" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li>entry<code>.arguments</code></li><li>entry<code>.cache_key</code></li><li>db<code>.toolchain_cache</code></li></ul><h4 id="writes-to-3" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to-3" aria-label="Permalink to &quot;Writes To&quot;">​</a></h4><ul><li>db<code>.toolchain_cache</code></li></ul><h4 id="usage-patterns-10" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-10" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Caching sanitized tool arguments for compile entries</li><li>Avoiding repeated sanitization of tool arguments</li></ul><h3 id="clore-extract-sanitize-driver-arguments" tabindex="-1"><code>clore::extract::sanitize_driver_arguments</code> <a class="header-anchor" href="#clore-extract-sanitize-driver-arguments" aria-label="Permalink to &quot;`clore::extract::sanitize_driver_arguments`&quot;">​</a></h3><p>Declaration: <code>extract/compiler.cppm:52</code></p><p>Definition: <code>extract/compiler.cppm:207</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p>该函数首先通过 <code>normalize_argument_path</code> 规范化 <code>entry.file</code> 与 <code>entry.directory</code> 得到 <code>source_path</code>，然后对 <code>entry.arguments</code> 执行 <code>std::erase_if</code>，移除那些非空、不以 <code>-</code> 开头且经相同规范化后与 <code>source_path</code> 相等的参数。这一过滤逻辑用于剔除与输入文件自身路径重复的参数（如显式传递的源文件名），保留编译选项和标志。核心依赖是 <code>normalize_argument_path</code>，它负责将相对路径或混合路径转换为统一的绝对形式以进行精确比较；内部不涉及复杂的状态或异常处理，仅依赖标准库容器算法和路径规范化工具。</p><h4 id="side-effects-9" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-9" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-9" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-9" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>entry.arguments</code></li><li><code>entry.file</code></li><li><code>entry.directory</code></li></ul><h4 id="usage-patterns-11" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-11" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>used to clean up compiler argument lists before invoking the driver</li><li>called to avoid duplicate source file arguments</li></ul><h3 id="clore-extract-sanitize-tool-arguments" tabindex="-1"><code>clore::extract::sanitize_tool_arguments</code> <a class="header-anchor" href="#clore-extract-sanitize-tool-arguments" aria-label="Permalink to &quot;`clore::extract::sanitize_tool_arguments`&quot;">​</a></h3><p>Declaration: <code>extract/compiler.cppm:54</code></p><p>Definition: <code>extract/compiler.cppm:221</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p><code>clore::extract::sanitize_tool_arguments</code> 的实现完全依赖于委托：它将接收到的 <code>CompileEntry</code> 引用传递给 <code>sanitize_driver_arguments</code>，再将结果直接传入 <code>strip_compiler_path</code>。内部控制流是线性的，没有分支、循环或错误处理；唯一的数据流是参数向量经过两次转换后的返回值。这两个被调用的函数分别承担了清理编译器特定参数和剥离可执行路径的核心工作，共同构成了整个函数的计算逻辑。</p><h4 id="side-effects-10" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-10" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-10" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-10" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li>const <code>CompileEntry</code> &amp;entry</li></ul><h4 id="usage-patterns-12" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-12" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Used in the extraction pipeline to normalize compile commands before parsing or analysis</li></ul><h3 id="clore-extract-strip-compiler-path" tabindex="-1"><code>clore::extract::strip_compiler_path</code> <a class="header-anchor" href="#clore-extract-strip-compiler-path" aria-label="Permalink to &quot;`clore::extract::strip_compiler_path`&quot;">​</a></h3><p>Declaration: <code>extract/compiler.cppm:47</code></p><p>Definition: <code>extract/compiler.cppm:181</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p>该函数接收一个代表编译器调用的参数向量，并返回移除了第一个元素（即编译器可执行路径）后的剩余参数。若输入参数不足两个元素（即没有后续参数），则返回一个空向量。控制流仅包含一个长度检查与一次向量切片操作，不依赖外部函数或数据结构，算法复杂度为线性复制。</p><h4 id="side-effects-11" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-11" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-11" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-11" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>args</code> parameter</li></ul><h4 id="usage-patterns-13" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-13" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Used to extract compiler flags from a compilation command, e.g., when processing <code>CompileEntry</code> arguments.</li></ul><h2 id="internal-structure" tabindex="-1">Internal Structure <a class="header-anchor" href="#internal-structure" aria-label="Permalink to &quot;Internal Structure&quot;">​</a></h2><p>模块 <code>extract:compiler</code> 围绕编译数据库的加载、条目规范化及编译器调用实例化进行分解。核心公开类型包括 <code>CompileEntry</code>（存储源文件、编译目录、参数列表及缓存字段）和 <code>CompilationDatabase</code>（维护条目列表与工具链缓存）。公开函数从 <code>load_compdb</code> 开始，逐层处理：先通过 <code>normalize_entry_file</code> 与 <code>sanitize_driver_arguments</code> 完成路径和参数的标准化，再通过 <code>ensure_cache_key</code> 建立唯一缓存标识，最后由 <code>query_toolchain_cached</code> 和 <code>create_compiler_instance</code> 将清理后的输入转化为可复用的编译器实例。内部处于匿名命名空间的辅助函数（如 <code>parse_compiler_invocation</code>、<code>try_hash_source_file</code>、<code>build_compile_signature_impl</code>）负责底层的路径哈希、参数解析与签名计算，确保公开接口的职责清晰且可测试。该模块仅导入 <code>std</code> 与 <code>support</code> 模块，依赖后者提供的文件 I/O、路径归一化及缓存键构造能力，自身则专注于编译器调用相关的解析、去重与实例化逻辑，形成从原始编译数据库到可用编译器实例的完整转换流水线。</p><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./../support/">Module support</a></li></ul>',198)])])}const u=a(r,[["render",i]]);export{m as __pageData,u as default};
